void NavigateWithAvoidance::publishCmd(double lin, double ang)
{
  if (!cmd_pub_) {
    return;
  }
  geometry_msgs::msg::Twist t;
  t.linear.x = lin;
  t.angular.z = ang;
  cmd_pub_->publish(t);
}

void NavigateWithAvoidance::publishStop()
{
  publishCmd(0.0, 0.0);
}

